package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class GsonHtmlSafeTest {

  @Test
  void testHtmlSafeTrue() throws Exception {
    // Use GsonBuilder to create Gson instance with htmlSafe = true
    Gson gson = new GsonBuilder().setHtmlSafe(true).create();

    boolean result = gson.htmlSafe();
    assertTrue(result);
  }

  @Test
  void testHtmlSafeFalse() throws Exception {
    // Use GsonBuilder to create Gson instance with htmlSafe = false
    Gson gson = new GsonBuilder().setHtmlSafe(false).create();

    boolean result = gson.htmlSafe();
    assertFalse(result);
  }
}
